visualizerParams.ghostCode:
#include <stdio.h>
#include <stdbool.h>

int main() {
    int n = 29;
    bool isPrime = true;
    if (n < 2) isPrime = false;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            isPrime = false;
            break;
        }
    }
    if (isPrime) printf("%d is prime\n", n);
    else printf("%d is not prime\n", n);
    return 0;
}

